template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Create a vector to hold the preview data
    std::vector<uint8_t> preview_buffer(bytes_to_preview);

    // Use the copy member function to copy data without advancing read pointer
    storage.copy(preview_buffer.data(), bytes_to_preview);

    return preview_buffer;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Use size() member function to get readable data size
    status.readable_size = storage.size();

    // Use free() member function to get available free space
    status.free_space = storage.free();

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use clear() member function to reset read and write offsets
    storage.clear();
}
