    EXPECT_EQ(5, obj5->id);
    EXPECT_EQ(6, obj6->id);
    EXPECT_DOUBLE_EQ(4.0, obj4->value);
    EXPECT_DOUBLE_EQ(5.0, obj5->value);
    EXPECT_DOUBLE_EQ(6.0, obj6->value);

    allocator.deallocate(obj6);
    allocator.deallocate(obj5);
    allocator.deallocate(obj4);
}

TEST(BlockAllocator, MultipleAllocations) {
    hexi::block_allocator<PoolObject, 5> allocator;
    std::vector<PoolObject*> objects;

    // Allocate up to capacity - each allocate() internally calls pop()
    for (int i = 0; i < 5; ++i) {
        objects.push_back(allocator.allocate(i, i * 10.0));
    }

    // Verify all allocations succeeded
    for (int i = 0; i < 5; ++i) {
        EXPECT_EQ(i, objects[i]->id);
        EXPECT_DOUBLE_EQ(i * 10.0, objects[i]->value);
    }

    // Deallocate all - each deallocate() internally calls push()
    for (auto* obj : objects) {
        allocator.deallocate(obj);
    }
}

