Based on the reference materials and detailed specifications, here's the complete implementation for the exam question:

```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <string_view>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: write sensor_id directly
        adaptor & sensor_id;

        // Write temperatures with native to little-endian conversion
        for (const auto& temp : temperatures) {
            auto converted = hexi::endian::conditional_reverse(temp, 
                                                              std::endian::native, 
                                                              std::endian::little);
            adaptor.write(converted);
        }

        // Write pressure with native to little-endian conversion
        auto converted_pressure = hexi::endian::conditional_reverse(pressure, 
                                                                   std::endian::native, 
                                                                   std::endian::little);
        adaptor.write(converted_pressure);
    }

    void deserialise(auto& adaptor) {
        // Deserialization: read sensor_id directly
        adaptor & sensor_id;

        // Read temperatures with little-endian to native conversion
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read pressure with little-endian to native conversion
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create a buffer to hold serialized data
    std::vector<uint8_t> buffer;

    // Create buffer_adaptor using init_empty_t for serialization
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer, hexi::init_empty_t{});

    // Create binary_stream with the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Call stream's serialise method with the data
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor for the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create binary_stream with the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Create MeasurementData object
    MeasurementData data;

    // Call stream's deserialise method with the object
    stream.deserialise(data);

    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    // Create binary_stream from the buffer
    hexi::binary_stream stream(buffer);

    // Use view to extract null-terminated sensor name
    std::string_view sensor_name = stream.view();

    // Use enforce_read_bounds to check if there's enough data for sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    uint32_t sensor_id;
    stream.read(&sensor_id);

    // Skip remaining data using skip
    stream.skip(buffer.size() - stream.total_read());

    return {sensor_id, sensor_name};
}
